class Solution:
    def reversePairs(self, nums):
        def sort_count(arr):
            if len(arr) <= 1:
                return arr, 0
            mid = len(arr) // 2
            left, lc = sort_count(arr[:mid])
            right, rc = sort_count(arr[mid:])
            count = lc + rc
            j = 0
            for x in left:
                while j < len(right) and x > 2 * right[j]:
                    j += 1
                count += j
            merged = []
            i = k = 0
            while i < len(left) and k < len(right):
                if left[i] <= right[k]:
                    merged.append(left[i]); i += 1
                else:
                    merged.append(right[k]); k += 1
            merged.extend(left[i:])
            merged.extend(right[k:])
            return merged, count
        return sort_count(nums)[1]

