var reversePairs = function(nums) {
    const sortCount = (arr) => {
        if (arr.length <= 1) return [arr, 0];
        const mid = arr.length >> 1;
        const [left, lc] = sortCount(arr.slice(0, mid));
        const [right, rc] = sortCount(arr.slice(mid));
        let count = lc + rc;
        let j = 0;
        for (const x of left) {
            while (j < right.length && x > 2 * right[j]) j++;
            count += j;
        }
        const merged = [];
        let i = 0, k = 0;
        while (i < left.length && k < right.length) {
            if (left[i] <= right[k]) merged.push(left[i++]);
            else merged.push(right[k++]);
        }
        while (i < left.length) merged.push(left[i++]);
        while (k < right.length) merged.push(right[k++]);
        return [merged, count];
    };
    return sortCount(nums)[1];
};
